var structuredData = {
	"contents": [
		{
			"heading": void 0,
			"content": "Next.js includes its own server with `next start` by default. If you have an existing backend, you can still use it with Next.js (this is not a custom server). A custom Next.js server allows you to programmatically start a server for custom patterns. The majority of the time, you will not need this approach. However, it's available if you need to eject."
		},
		{
			"heading": void 0,
			"content": "> **Good to know**:\n>\n> * Before deciding to use a custom server, keep in mind that it should only be used when the integrated router of Next.js can't meet your app requirements. A custom server will remove important performance optimizations, like &#x2A;*Automatic Static Optimization.**\n> * When using standalone output mode, it does not trace custom server files. This mode outputs a separate minimal `server.js` file, instead. These cannot be used together."
		},
		{
			"heading": void 0,
			"content": "Take a look at the following example of a custom server:"
		},
		{
			"heading": void 0,
			"content": "> `server.js` does not run through the Next.js Compiler or bundling process. Make sure the syntax and source code this file requires are compatible with the current Node.js version you are using. View an example."
		},
		{
			"heading": void 0,
			"content": "To run the custom server, you'll need to update the `scripts` in `package.json` like so:"
		},
		{
			"heading": void 0,
			"content": "Alternatively, you can set up `nodemon` (example). The custom server uses the following import to connect the server with the Next.js application:"
		},
		{
			"heading": void 0,
			"content": "The above `next` import is a function that receives an object with the following options:"
		},
		{
			"heading": void 0,
			"content": "Option"
		},
		{
			"heading": void 0,
			"content": "Type"
		},
		{
			"heading": void 0,
			"content": "Description"
		},
		{
			"heading": void 0,
			"content": "`conf`"
		},
		{
			"heading": void 0,
			"content": "`Object`"
		},
		{
			"heading": void 0,
			"content": "The same object you would use in `next.config.js`. Defaults to `{}`"
		},
		{
			"heading": void 0,
			"content": "`dev`"
		},
		{
			"heading": void 0,
			"content": "`Boolean`"
		},
		{
			"heading": void 0,
			"content": "(*Optional*) Whether or not to launch Next.js in dev mode. Defaults to `false`"
		},
		{
			"heading": void 0,
			"content": "`dir`"
		},
		{
			"heading": void 0,
			"content": "`String`"
		},
		{
			"heading": void 0,
			"content": "(*Optional*) Location of the Next.js project. Defaults to `'.'`"
		},
		{
			"heading": void 0,
			"content": "`quiet`"
		},
		{
			"heading": void 0,
			"content": "`Boolean`"
		},
		{
			"heading": void 0,
			"content": "(*Optional*) Hide error messages containing server information. Defaults to `false`"
		},
		{
			"heading": void 0,
			"content": "`hostname`"
		},
		{
			"heading": void 0,
			"content": "`String`"
		},
		{
			"heading": void 0,
			"content": "(*Optional*) The hostname the server is running behind"
		},
		{
			"heading": void 0,
			"content": "`port`"
		},
		{
			"heading": void 0,
			"content": "`Number`"
		},
		{
			"heading": void 0,
			"content": "(*Optional*) The port the server is running behind"
		},
		{
			"heading": void 0,
			"content": "`httpServer`"
		},
		{
			"heading": void 0,
			"content": "`node:http#Server`"
		},
		{
			"heading": void 0,
			"content": "(*Optional*) The HTTP Server that Next.js is running behind"
		},
		{
			"heading": void 0,
			"content": "`turbo`"
		},
		{
			"heading": void 0,
			"content": "`Boolean`"
		},
		{
			"heading": void 0,
			"content": "(*Optional*) Enable Turbopack"
		},
		{
			"heading": void 0,
			"content": "The returned `app` can then be used to let Next.js handle requests as required."
		},
		{
			"heading": "disabling-file-system-routing",
			"content": "By default, `Next` will serve each file in the `pages` folder under a pathname matching the filename. If your project uses a custom server, this behavior may result in the same content being served from multiple paths, which can present problems with SEO and UX."
		},
		{
			"heading": "disabling-file-system-routing",
			"content": "To disable this behavior and prevent routing based on files in `pages`, open `next.config.js` and disable the `useFileSystemPublicRoutes` config:"
		},
		{
			"heading": "disabling-file-system-routing",
			"content": "> Note that `useFileSystemPublicRoutes` disables filename routes from SSR; client-side routing may still access those paths. When using this option, you should guard against navigation to routes you do not want programmatically."
		},
		{
			"heading": "disabling-file-system-routing",
			"content": "> You may also wish to configure the client-side router to disallow client-side redirects to filename routes; for that refer to `router.beforePopState`."
		}
	],
	"headings": [{
		"id": "disabling-file-system-routing",
		"content": "Disabling file-system routing"
	}]
};
